{
  "permissions": {
    "allow": [
      "Bash(mkdir:*)",
      "Bash(npx prettier --write:*)",
      "Read(.claude/**)",
      "Write(.claude/**)",
      "Edit(.claude/**)",
      "Read(tasks/**)",
      "Write(tasks/**)",
      "Edit(tasks/**)",
      "Bash(git add:*)",
      "SlashCommand(/task:architect task-1764889273)",
      "Bash(yarn type-check:*)",
      "Bash(cat:*)",
      "Bash(npx tsc --noEmit)",
      "Bash(yarn lint:*)",
      "Bash(yarn test:*)"
    ],
    "deny": [
      "Read(.env)",
      "Read(../.env)"
    ],
    "ask": [],
    "defaultMode": "default"
  },
  "alwaysThinkingEnabled": true,
  "hooks": {
    "PreToolUse": [
      {
        "matcher": "Read",
        "hooks": [
          {
            "type": "command",
            "command": "~/.claude-code-docs/claude-docs-helper.sh hook-check"
          }
        ]
      }
    ]
  }
}

